package com.cognizant.springlearn.service; import java.util.*; import java.util.concurrent.*; import org.springframework.stereotype.*; import com.cognizant.springlearn.model.*;
@Service public class CountryService {private final Map<String,Country> countries=new ConcurrentHashMap<>(); public CountryService(){for(Country c:List.of(new Country("IN","India"),new Country("US","United States"),new Country("DE","Germany"),new Country("JP","Japan")))countries.put(c.code(),c);} public List<Country> all(){return countries.values().stream().sorted(Comparator.comparing(Country::code)).toList();} public Country get(String code){Country c=countries.get(code.toUpperCase());if(c==null)throw new NoSuchElementException("Country not found");return c;} public Country add(Country c){if(countries.putIfAbsent(c.code().toUpperCase(),c)!=null)throw new IllegalArgumentException("Country already exists");return c;} public Country update(Country c){if(!countries.containsKey(c.code().toUpperCase()))throw new NoSuchElementException("Country not found");countries.put(c.code().toUpperCase(),c);return c;} public void delete(String code){get(code);countries.remove(code.toUpperCase());}}
